598→    protected Processor createChildProcessor(boolean mandatory) throws Exception {
   599→        Processor children = null;
   600→        // at first use custom factory
   601→        final ProcessorFactory processorFactory = PluginHelper.getProcessorFactory(camelContext);
   602→        if (processorFactory != null) {
   603→            children = processorFactory.createChildProcessor(route,
   604→                    definition, mandatory);
   605→        }
   606→        // fallback to default implementation if factory did not create the
   607→        // child
   608→        if (children == null) {
   609→            children = createOutputsProcessor();
   610→        }
   611→
   612→        if (children == null && mandatory) {
   613→            throw new IllegalArgumentException("Definition has no children on " + definition);
   614→        }
   615→        return children;
   616→    }
   617→
   618→    public void addRoutes() throws Exception {
   619→        Channel processor = makeProcessor();
   620→        if (processor == null) {
   621→            // no processor to add
   622→            return;
   623→        }
   624→
   625→        // are we routing to an endpoint interceptor, if so we should not
   626→        // add it as an event driven
   627→        // processor as we use the producer to trigger the interceptor
   628→        boolean endpointInterceptor = processor.getNextProcessor() instanceof InterceptEndpointProcessor;
   629→
   630→        // only add regular processors as event driven
   631→        if (endpointInterceptor) {
   632→            LOG.debug("Endpoint interceptor should not be added as an event driven consumer route: {}", processor);
   633→        } else {
   634→            LOG.trace("Adding event driven processor: {}", processor);
   635→            route.getEventDrivenProcessors().add(processor);
   636→        }
   637→    }
   638→
   639→    /**
   640→     * Wraps the child processor in whatever necessary interceptors and error handlers
   641→     */
   642→    public Channel wrapProcessor(Processor processor) throws Exception {
   643→        // don't double wrap
   644→        if (processor instanceof Channel channel) {
   645→            return channel;
   646→        }
   647→        return wrapChannel(processor, null);
   648→    }
   649→
   650→    protected Channel wrapChannel(Processor processor, ProcessorDefinition<?> child) throws Exception {
   651→        return wrapChannel(processor, child, definition.getInheritErrorHandler());
   652→    }
   653→
   654→    protected Channel wrapChannel(Processor processor, ProcessorDefinition<?> child, Boolean inheritErrorHandler)
   655→            throws Exception {
   656→        // put a channel in between this and each output to control the route flow logic
   657→        Channel channel = PluginHelper.getInternalProcessorFactory(camelContext)
   658→                .createChannel(camelContext);
   659→
   660→        // add interceptor strategies to the channel must be in this order:
   661→        // camel context, route context, local
